-- sequence_no는 트리거가 자동 채번
INSERT INTO vocs (id, title, body, status, priority, reporter_id, assignee_id, system_id, menu_id, voc_type_id, source) VALUES
  ('50000000-0000-0000-0000-000000000001', '대시보드 로딩 속도 개선 요청', '분석 시스템 대시보드가 데이터 로드 시 10초 이상 걸립니다.',
   '접수', 'high',   '00000000-0000-0000-0000-000000000003', NULL, '10000000-0000-0000-0000-000000000001', '20000000-0000-0000-0000-000000000001', '30000000-0000-0000-0000-000000000003', 'manual'),
  ('50000000-0000-0000-0000-000000000002', '리포트 다운로드 오류', 'CSV 다운로드 버튼 클릭 시 500 에러가 발생합니다.',
   '검토중', 'urgent', '00000000-0000-0000-0000-000000000003', '00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000001', '20000000-0000-0000-0000-000000000002', '30000000-0000-0000-0000-000000000001', 'manual'),
  ('50000000-0000-0000-0000-000000000003', '생산계획 날짜 필터 버그', '시작일과 종료일 역전 시 빈 결과 대신 에러 메시지 없이 전체 데이터를 반환합니다.',
   '처리중', 'medium', '00000000-0000-0000-0000-000000000003', '00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000004', '30000000-0000-0000-0000-000000000001', 'manual'),
  ('50000000-0000-0000-0000-000000000004', '품질관리 기능 추가 요청', '불량 유형별 트렌드 차트 기능이 필요합니다.',
   '완료', 'low',    '00000000-0000-0000-0000-000000000003', '00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000006', '30000000-0000-0000-0000-000000000002', 'manual'),
  ('50000000-0000-0000-0000-000000000005', '실적 데이터 오차 문의', '목표 대비 실적이 음수로 표시되는 경우가 있습니다.',
   '드랍', 'medium', '00000000-0000-0000-0000-000000000003', NULL, '10000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000005', '30000000-0000-0000-0000-000000000004', 'manual'),
  ('50000000-0000-0000-0000-000000000006', '권한 오류 — 일반 사용자 관리자 메뉴 접근', '일반 사용자가 관리자 전용 설정 메뉴에 접근 가능합니다.',
   '접수', 'urgent', '00000000-0000-0000-0000-000000000003', NULL, '10000000-0000-0000-0000-000000000001', '20000000-0000-0000-0000-000000000003', '30000000-0000-0000-0000-000000000001', 'manual'),
  ('50000000-0000-0000-0000-000000000007', '분석 리포트 필터 UI 개선', '현재 드롭다운 방식 필터를 멀티셀렉트로 변경 요청합니다.',
   '검토중', 'low',   '00000000-0000-0000-0000-000000000003', '00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000001', '20000000-0000-0000-0000-000000000002', '30000000-0000-0000-0000-000000000003', 'manual'),
  ('50000000-0000-0000-0000-000000000008', '생산계획 Jira 이관 데이터 정합성', 'Jira에서 이관된 VOC 중 담당자가 비어 있는 항목이 있습니다.',
   '처리중', 'high',  '00000000-0000-0000-0000-000000000002', '00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000004', '30000000-0000-0000-0000-000000000004', 'import'),
  ('50000000-0000-0000-0000-000000000009', '대시보드 위젯 순서 저장 안 됨', '페이지 새로고침 후 위젯 순서가 초기화됩니다.',
   '완료', 'medium', '00000000-0000-0000-0000-000000000003', '00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000001', '20000000-0000-0000-0000-000000000001', '30000000-0000-0000-0000-000000000001', 'manual'),
  ('50000000-0000-0000-0000-000000000010', '기타 — 로그인 후 리다이렉트 오류', '로그인 완료 후 이전 페이지가 아닌 홈으로 이동합니다.',
   '접수', 'medium', '00000000-0000-0000-0000-000000000003', NULL, '10000000-0000-0000-0000-000000000001', '20000000-0000-0000-0000-000000000003', '30000000-0000-0000-0000-000000000004', 'manual')
ON CONFLICT (id) DO NOTHING;

-- vocs (추가 20건 — id: 000000000011 ~ 000000000030)
-- status 분포: 접수(5), 검토중(5), 처리중(4), 완료(4), 드랍(2)
-- priority 분포: urgent(3), high(6), medium(7), low(4)
INSERT INTO vocs (id, title, body, status, priority, reporter_id, assignee_id, system_id, menu_id, voc_type_id, source) VALUES
  ('50000000-0000-0000-0000-000000000011', '분석 대시보드 KPI 위젯 수치 오류',
   '금월 매출 KPI 위젯이 전월 데이터를 표시하고 있습니다. 집계 쿼리의 날짜 범위 조건이 잘못 적용된 것으로 보이며, 매일 아침 조회 시마다 재현됩니다.',
   '처리중', 'urgent', '00000000-0000-0000-0000-000000000003', '00000000-0000-0000-0000-000000000002',
   '10000000-0000-0000-0000-000000000001', '20000000-0000-0000-0000-000000000001', '30000000-0000-0000-0000-000000000001', 'manual'),

  ('50000000-0000-0000-0000-000000000012', '리포트 페이지 엑셀 내보내기 인코딩 깨짐',
   '엑셀 파일로 내보낼 때 한글 컬럼명이 모두 물음표(???)로 표시됩니다. UTF-8 BOM 설정이 누락된 것으로 추정됩니다.',
   '검토중', 'high', '00000000-0000-0000-0000-000000000003', '00000000-0000-0000-0000-000000000002',
   '10000000-0000-0000-0000-000000000001', '20000000-0000-0000-0000-000000000002', '30000000-0000-0000-0000-000000000001', 'manual'),

  ('50000000-0000-0000-0000-000000000013', '생산계획 모바일 화면 레이아웃 깨짐',
   '태블릿(1024px) 이하 해상도에서 생산계획 캘린더 뷰가 컬럼 헤더와 셀이 겹쳐 보입니다. 현장 작업자들이 모바일로 조회하는 경우가 많아 빠른 수정이 필요합니다.',
   '접수', 'high', '00000000-0000-0000-0000-000000000003', NULL,
   '10000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000004', '30000000-0000-0000-0000-000000000003', 'manual'),

  ('50000000-0000-0000-0000-000000000014', '실적관리 목표 달성률 소수점 절삭 오류',
   '달성률이 99.9%일 때 UI에서 100%로 반올림 표시되어 목표 초과 달성처럼 보입니다. 소수점 첫째 자리까지 표기하도록 변경 요청합니다.',
   '완료', 'medium', '00000000-0000-0000-0000-000000000003', '00000000-0000-0000-0000-000000000002',
   '10000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000005', '30000000-0000-0000-0000-000000000003', 'manual'),

  ('50000000-0000-0000-0000-000000000015', '품질관리 불량 원인 카테고리 추가 요청',
   '현재 불량 원인이 "설비", "작업자", "원자재" 3가지뿐입니다. "설계" 카테고리를 추가해야 품질 분석 정확도가 높아집니다.',
   '검토중', 'medium', '00000000-0000-0000-0000-000000000003', '00000000-0000-0000-0000-000000000002',
   '10000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000006', '30000000-0000-0000-0000-000000000002', 'manual'),

  ('50000000-0000-0000-0000-000000000016', '분석 시스템 세션 만료 후 흰 화면',
   '로그인 세션이 만료되면 에러 메시지 없이 흰 화면만 표시됩니다. 자동으로 로그인 페이지로 리다이렉트되어야 합니다.',
   '접수', 'urgent', '00000000-0000-0000-0000-000000000003', NULL,
   '10000000-0000-0000-0000-000000000001', '20000000-0000-0000-0000-000000000003', '30000000-0000-0000-0000-000000000001', 'manual'),

  ('50000000-0000-0000-0000-000000000017', '생산계획 대량 등록 CSV 임포트 기능 요청',
   '생산계획을 건별로 등록하는 데 시간이 많이 소요됩니다. 엑셀/CSV 양식으로 한 번에 업로드할 수 있는 기능을 요청합니다. 월 기준 약 500건 이상 등록이 필요합니다.',
   '검토중', 'high', '00000000-0000-0000-0000-000000000002', '00000000-0000-0000-0000-000000000002',
   '10000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000004', '30000000-0000-0000-0000-000000000002', 'manual'),

  ('50000000-0000-0000-0000-000000000018', '실적관리 부서별 필터 적용 시 페이지 응답 없음',
   '부서 필터를 3개 이상 복합 선택하면 API 응답이 30초 이상 걸리거나 타임아웃 됩니다. 인덱스 최적화 또는 쿼리 개선이 필요합니다.',
   '처리중', 'urgent', '00000000-0000-0000-0000-000000000003', '00000000-0000-0000-0000-000000000002',
   '10000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000005', '30000000-0000-0000-0000-000000000001', 'manual'),

  ('50000000-0000-0000-0000-000000000019', '분석 리포트 날짜 범위 기본값 설정 요청',
   '리포트 조회 시 날짜 범위 기본값이 없어 매번 수동 입력해야 합니다. 최근 1개월을 기본값으로 설정해 주시면 업무 효율이 올라갑니다.',
   '완료', 'low', '00000000-0000-0000-0000-000000000003', '00000000-0000-0000-0000-000000000002',
   '10000000-0000-0000-0000-000000000001', '20000000-0000-0000-0000-000000000002', '30000000-0000-0000-0000-000000000003', 'manual'),

  ('50000000-0000-0000-0000-000000000020', '품질관리 검사 이력 삭제 후 복구 불가 문의',
   '실수로 검사 이력 데이터를 삭제했는데 복구할 방법이 없습니다. 소프트 삭제(soft delete) 또는 휴지통 기능을 추가해 주시면 이런 사고를 방지할 수 있을 것 같습니다.',
   '드랍', 'low', '00000000-0000-0000-0000-000000000003', NULL,
   '10000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000006', '30000000-0000-0000-0000-000000000004', 'manual'),

  ('50000000-0000-0000-0000-000000000021', '대시보드 접속 시 브라우저 콘솔 에러 다수 발생',
   'Chrome DevTools 콘솔에서 "Cannot read properties of undefined" 에러가 반복 출력됩니다. 기능 동작에는 이상 없으나 로그가 오염되어 실제 오류 감지가 어렵습니다.',
   '접수', 'low', '00000000-0000-0000-0000-000000000003', NULL,
   '10000000-0000-0000-0000-000000000001', '20000000-0000-0000-0000-000000000001', '30000000-0000-0000-0000-000000000001', 'manual'),

  ('50000000-0000-0000-0000-000000000022', '생산관리 기타 메뉴 공지사항 게시 기능 요청',
   '공지사항을 별도 시스템 없이 생산관리 메뉴 내에서 공유하고 싶습니다. 간단한 게시판 형태로 공지 등록 및 조회가 가능하면 충분합니다.',
   '드랍', 'low', '00000000-0000-0000-0000-000000000002', NULL,
   '10000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000007', '30000000-0000-0000-0000-000000000002', 'manual'),

  ('50000000-0000-0000-0000-000000000023', '실적관리 그래프 범례 텍스트 잘림',
   '실적 대비 목표 차트에서 범례(legend) 텍스트가 12자 이상일 때 말줄임표(...)로 잘립니다. 전체 텍스트가 표시되도록 툴팁이나 래핑 처리를 요청합니다.',
   '완료', 'medium', '00000000-0000-0000-0000-000000000003', '00000000-0000-0000-0000-000000000002',
   '10000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000005', '30000000-0000-0000-0000-000000000003', 'manual'),

  ('50000000-0000-0000-0000-000000000024', '품질관리 검사 담당자 이메일 알림 설정 요청',
   '검사 결과가 불합격 판정될 때 담당자에게 이메일 알림이 자동으로 전송되면 좋겠습니다. 현재는 직접 시스템에 접속해 결과를 확인해야 합니다.',
   '검토중', 'medium', '00000000-0000-0000-0000-000000000003', '00000000-0000-0000-0000-000000000002',
   '10000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000006', '30000000-0000-0000-0000-000000000002', 'manual'),

  ('50000000-0000-0000-0000-000000000025', '분석 시스템 기타 메뉴 링크 404 오류',
   '분석 시스템 > 기타 메뉴의 "외부 연계 현황" 링크를 클릭하면 404 페이지로 이동합니다. 해당 페이지가 삭제된 것인지 URL이 변경된 것인지 확인이 필요합니다.',
   '접수', 'medium', '00000000-0000-0000-0000-000000000003', NULL,
   '10000000-0000-0000-0000-000000000001', '20000000-0000-0000-0000-000000000003', '30000000-0000-0000-0000-000000000004', 'manual'),

  ('50000000-0000-0000-0000-000000000026', '생산계획 잔여 수량 자동 계산 오류',
   '일부 품목에서 잔여 수량이 음수(-3)로 계산됩니다. 생산 실적 입력 순서에 따라 집계 로직이 달라지는 것으로 보입니다.',
   '처리중', 'high', '00000000-0000-0000-0000-000000000003', '00000000-0000-0000-0000-000000000002',
   '10000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000004', '30000000-0000-0000-0000-000000000001', 'manual'),

  ('50000000-0000-0000-0000-000000000027', '분석 대시보드 인쇄 레이아웃 깨짐',
   'Ctrl+P 또는 브라우저 인쇄 기능 사용 시 위젯 레이아웃이 무너지고 차트가 잘립니다. 경영진 보고 시 캡처 대신 직접 인쇄할 수 있도록 print 스타일시트 적용을 요청합니다.',
   '검토중', 'medium', '00000000-0000-0000-0000-000000000002', '00000000-0000-0000-0000-000000000002',
   '10000000-0000-0000-0000-000000000001', '20000000-0000-0000-0000-000000000001', '30000000-0000-0000-0000-000000000003', 'manual'),

  ('50000000-0000-0000-0000-000000000028', '실적관리 데이터 수정 이력 조회 기능 요청',
   '실적 데이터가 누군가 임의로 수정되는 사례가 있었습니다. 수정 시각, 수정자, 변경 전후 값을 조회할 수 있는 이력 기능이 필요합니다.',
   '접수', 'high', '00000000-0000-0000-0000-000000000002', NULL,
   '10000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000005', '30000000-0000-0000-0000-000000000002', 'manual'),

  ('50000000-0000-0000-0000-000000000029', '품질관리 불량 통계 월별 비교 차트 추가',
   '현재 일별 불량 추이만 제공됩니다. 월별 불량률 비교 차트를 추가하면 계절적 패턴 분석에 유용할 것입니다.',
   '완료', 'medium', '00000000-0000-0000-0000-000000000003', '00000000-0000-0000-0000-000000000002',
   '10000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000006', '30000000-0000-0000-0000-000000000002', 'manual'),

  ('50000000-0000-0000-0000-000000000030', '분석 리포트 공유 링크 만료 시간 설정 요청',
   '리포트 공유 링크가 무기한 유효하여 보안 우려가 있습니다. 1일/7일/30일 등 만료 시간을 설정할 수 있는 옵션 추가를 요청합니다.',
